/// Solves the N-Queens problem, returning all valid board configurations.
/// Each configuration is represented as a Vec<usize> where the index is the row
/// and the value is the column position of the queen.
pub fn solve_n_queens(n: usize) -> Vec<Vec<usize>> {
    let mut solutions = Vec::new();
    let mut board = Vec::with_capacity(n);
    let mut cols = vec![false; n];
    let mut diag1 = vec![false; 2 * n]; // Tracks (row - col + n)
    let mut diag2 = vec![false; 2 * n]; // Tracks (row + col)

    backtrack(0, n, &mut board, &mut cols, &mut diag1, &mut diag2, &mut solutions);
    solutions
}

fn backtrack(
    row: usize,
    n: usize,
    board: &mut Vec<usize>,
    cols: &mut [bool],
    diag1: &mut [bool],
    diag2: &mut [bool],
    solutions: &mut Vec<Vec<usize>>,
) {
    if row == n {
        solutions.push(board.clone());
        return;
    }

    for col in 0..n {
        let d1 = row + n - col;
        let d2 = row + col;

        if !cols[col] && !diag1[d1] && !diag2[d2] {
            board.push(col);
            cols[col] = true;
            diag1[d1] = true;
            diag2[d2] = true;

            backtrack(row + 1, n, board, cols, diag1, diag2, solutions);

            cols[col] = false;
            diag1[d1] = false;
            diag2[d2] = false;
            board.pop();
        }
    }
}

